var items = $input.all();
if (!items || items.length === 0 || !items[0].json.id) return [];
return items;

var items = $input.all();
var msg = 'CAPTURE GATE REVIEW — ' + new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'short', day: 'numeric'}) + '\n\n';
var criticalCount = 0;

for (var i = 0; i < items.length; i++) {
  var cp = items[i].json;
  var fixes = [];
  try { fixes = typeof cp.critical_fixes === 'string' ? JSON.parse(cp.critical_fixes) : (cp.critical_fixes || []); } catch(e) { fixes = []; }
  var openCritical = fixes.filter(function(f) { return f.status === 'OPEN' && f.severity === 'CRITICAL'; });
  criticalCount += openCritical.length;

  var icon = openCritical.length > 0 ? '🔴' : '🟢';
  msg += icon + ' ' + cp.opportunity + '\n';
  msg += '   $' + (cp.contract_value / 1000000).toFixed(1) + 'M | ' + (cp.priority || 'Standard') + ' | PWin: ' + (cp.pwin || '?') + '% | ' + (cp.current_phase || cp.stage) + '\n';

  if (openCritical.length > 0) {
    msg += '   CRITICAL FIXES OPEN:\n';
    for (var j = 0; j < openCritical.length; j++) {
      msg += '   ⚠️ ' + openCritical[j].item + '\n';
    }
  }

  var risks = [];
  try { risks = typeof cp.risks === 'string' ? JSON.parse(cp.risks) : (cp.risks || []); } catch(e) { risks = []; }
  var critRisks = risks.filter(function(r) { return r.impact === 'CRITICAL' || r.impact === 'HIGH'; });
  if (critRisks.length > 0) {
    msg += '   HIGH/CRITICAL RISKS: ' + critRisks.length + '\n';
  }
  msg += '\n';
}

msg += 'Total: ' + items.length + ' active proposals | ' + criticalCount + ' open critical fixes';

return [{ json: { message: msg, proposal_count: items.length, critical_fixes: criticalCount } }];
